mapper.insert:
/* wms-master-itemgroup-sql-oracle.xml - insertInterfaceItempgroup */
INSERT INTO TWORK_INTF_ICGRP_RCV (
	   CTKEY			/* 센터코드 */
	 , OWKEY			/* 화주코드 */
	 , ICGRPKEY			/* 상품그룹코드 */
	 , ICGRPTYPECD		/* 상품그룹유형코드 */
	 , ICGRPNM			/* 상품그룹명 */
	 , CLOSDATE			/* 종료일시 */
	 , DELYN			/* 삭제여부 */
	 , PRCSYN			/* 처리여부 */
	 , PRCSDATE			/* 처리일시 */
	 , RCVDATE			/* 수신일시 */
	 , INSERTDATE		/* 입력일시 */
	 , INSERTURKEY		/* 입력자 */
	 , UPDATEDATE		/* 수정일시 */
	 , UPDATEURKEY		/* 수정자 */
	 )
VALUES (
	   #{ctkey}
	 , #{owkey}
	 , #{icgrpkey}
	 , #{icgrptypecd}
	 , #{icgrpnm}
	 , SUBSTR(#{closdate}, 1, 14)
	 , #{delyn}
	 , 'N'
	 , NULL
	 , #{sysdate}
	 , #{sysdate}
	 , #{surkey}
	 , #{sysdate}
	 , #{surkey}
	 )

/* wms-master-itemgroup-sql-oracle.xml - insertTworkMstIcgr */
INSERT INTO TWORK_MST_ICGR (
	   CTKEY			/* 센터 코드 */
	 , OWKEY			/* 화주 코드 */
	 , ICGRPKEY			/* 물품 그룹 코드 */
	 , ICGRPTYPECD		/* 물품 그룹 유형 */
	 , ICGRPNM			/* 물품 그룹명 */
	 , CLOSDATE			/* 종료 일시 */
	 , INSERTDATE		/* 입력 일시 */
	 , INSERTURKEY		/* 입력 사용자 ID */
	 , UPDATEDATE		/* 수정 일시 */
	 , UPDATEURKEY		/* 수정 사용자 ID */
	 )
VALUES (
	   #{ctkey}
	 , #{owkey}
	 , #{icgrpkey}
	 , #{icgrptypecd}
	 , #{icgrpnm}
	 , SUBSTR(#{closdate}, 1, 14)
	 , #{sysdate}
	 , #{surkey}
	 , #{sysdate}
	 , #{surkey}
	 )
